const ADLER_BASE: u32 = 65521;
const ADLER_NMAX: usize = 5552;

/// Compute the RFC 1950 Adler-32 checksum.
/// `seed` is the previous checksum (use 1 to start fresh).
pub fn adler32(seed: u32, buf: &[u8]) -> u32 {
    let mut s1 = seed & 0xFFFF;
    let mut s2 = (seed >> 16) & 0xFFFF;
    let mut i = 0;
    let len = buf.len();
    while i < len {
        let k = core::cmp::min(len - i, ADLER_NMAX);
        for _ in 0..k {
            s1 += buf[i] as u32;
            s2 += s1;
            i += 1;
        }
        s1 %= ADLER_BASE;
        s2 %= ADLER_BASE;
    }
    (s2 << 16) | s1
}
